// Deterministic 30-day dashboard data (no randomness, stable demo).
var LV_START = new Date('2024-03-01').getTime()
var LV_DAY = 86400000
function ordersData() {
  var out = []
  for (var i = 0; i < 30; i++) {
    var v = 60 + 30 * Math.sin(i / 3.3) + 14 * Math.sin(i / 1.7) + i * 0.6
    out.push([LV_START + i * LV_DAY, Math.round(v)])
  }
  return out
}
function valueData() {
  var out = []
  for (var i = 0; i < 30; i++) {
    // average order value, loosely anti-correlated with volume
    var v = 120 - 22 * Math.sin(i / 3.3) + 10 * Math.cos(i / 2.1)
    out.push([LV_START + i * LV_DAY, Math.round(v)])
  }
  return out
}

// Shared by the vanilla-js, React and Vue builds.
function fmt(ts) {
  return new Date(ts).toISOString().slice(0, 10)
}

var options = {
  series: [{ name: 'Orders', data: ordersData() }],
  chart: {
    id: 'orders',
    height: 250,
    type: 'bar',
    group: 'sales',
    fontFamily: 'Helvetica, Arial, sans-serif',
    animations: { enabled: false },
    link: { enabled: true, dimOpacity: 0.16 },
    selection: { enabled: true },
    toolbar: {
      autoSelected: 'selection',
      tools: {
        selection: true,
        zoom: false,
        pan: false,
        reset: false,
        download: false,
      },
    },
  },
  colors: ['#6366f1'],
  plotOptions: { bar: { columnWidth: '60%', borderRadius: 2 } },
  dataLabels: { enabled: false },
  title: { text: 'Daily orders (brush a range here)', align: 'left' },
  xaxis: { type: 'datetime' },
}

var chart = new ApexCharts(document.querySelector('#chart'), options)
chart.render()

var options1 = {
  series: [{ name: 'Avg value', data: valueData() }],
  chart: {
    id: 'value',
    height: 250,
    type: 'scatter',
    group: 'sales',
    fontFamily: 'Helvetica, Arial, sans-serif',
    animations: { enabled: false },
    link: { enabled: true, dimOpacity: 0.16 },
    zoom: { enabled: false },
    toolbar: { show: false },
  },
  colors: ['#0ea5e9'],
  markers: { size: 6 },
  title: { text: 'Avg order value (crossfiltered)', align: 'left' },
  xaxis: { type: 'datetime' },
  yaxis: {
    labels: {
      formatter: function (v) {
        return '$' + Math.round(v)
      },
    },
  },
}

var chart1 = new ApexCharts(document.querySelector('#chart2'), options1)
chart1.render()

// charts[0] = orders (brush source), charts[1] = value (target).
// The generated file exposes each chart as chart, chart1, chart2, ...
// (fmt lives in the shared head script.)
var readout = document.getElementById('readout')

chart.addEventListener('crossFilter', function (c, opts) {
  readout.textContent =
    'Filtered: ' + fmt(opts.xaxis.min) + ' to ' + fmt(opts.xaxis.max)
})

document.getElementById('clear').addEventListener('click', function () {
  chart.clearCrossfilter()
  readout.textContent = 'Cleared'
})

.wrap {
