  margin: 12px auto;
  font-family: sans-serif;
}
.bar {
  display: flex;
  gap: 12px;
  align-items: center;
  flex-wrap: wrap;
  margin-bottom: 4px;
}
.bar button {
  padding: 6px 13px;
  cursor: pointer;
  border: 1px solid #6366f1;
  color: #4338ca;
  background: #fff;
  border-radius: 6px;
  font-size: 13px;
  font-weight: 600;
}
